import React, { useState } from 'react';
import { useAuth } from '../auth/AuthContext';
import { apiRequest } from '../api/client';

const initialDonor = {
  can_donate_blood: true,
  organ_types: 'KIDNEY',
  organ_donation_registered: true,
  preferred_donation_time: 'MORNING',
  profile: {
    first_name: '',
    last_name: '',
    date_of_birth: '1990-01-01',
    gender: 'OTHER',
    address: '',
    city: '',
    state: '',
    postal_code: '',
    country: 'India',
    latitude: '19.0760',
    longitude: '72.8777',
    blood_group: 'O+',
    emergency_contact_name: '',
    emergency_contact_phone: '',
  },
};

function DonorPage() {
  const { token, setFlash } = useAuth();
  const [form, setForm] = useState(initialDonor);
  const [donorMe, setDonorMe] = useState(null);
  const [nearby, setNearby] = useState([]);

  function updateProfileField(field, value) {
    setForm((prev) => ({
      ...prev,
      profile: {
        ...prev.profile,
        [field]: value,
      },
    }));
  }

  async function createProfile(event) {
    event.preventDefault();
    try {
      const payload = {
        ...form,
        organ_types: form.organ_types
          .split(',')
          .map((x) => x.trim())
          .filter(Boolean),
        profile: {
          ...form.profile,
          latitude: Number(form.profile.latitude),
          longitude: Number(form.profile.longitude),
        },
      };

      await apiRequest('/donors/register', {
        method: 'POST',
        token,
        body: payload,
      });

      setFlash({ type: 'success', text: 'Donor profile created successfully.' });
      await loadDonorProfile();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadDonorProfile() {
    try {
      const data = await apiRequest('/donors/me', { token });
      setDonorMe(data);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function toggleAvailability() {
    if (!donorMe) {
      setFlash({ type: 'error', text: 'Load donor profile first.' });
      return;
    }

    try {
      await apiRequest('/donors/me/availability', {
        method: 'PUT',
        token,
        body: {
          is_available: !donorMe.is_available,
        },
      });
      setFlash({ type: 'success', text: `Availability updated to ${!donorMe.is_available}.` });
      await loadDonorProfile();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadNearby() {
    try {
      const lat = Number(form.profile.latitude);
      const lng = Number(form.profile.longitude);
      const blood = encodeURIComponent(form.profile.blood_group || '');
      const data = await apiRequest(
        `/donors/nearby?latitude=${lat}&longitude=${lng}&radius_km=25&blood_group=${blood}`,
        { token }
      );
      setNearby(data.items || []);
      setFlash({ type: 'success', text: `Found ${data.count || 0} nearby donors.` });
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  return (
    <section className="panel full">
      <h2>Donor Center</h2>
      <p className="muted-text">
        Create your donor profile, keep your status up to date, and monitor nearby donor network data.
      </p>

      <form onSubmit={createProfile} className="form-grid">
        <input placeholder="First Name" value={form.profile.first_name} onChange={(e) => updateProfileField('first_name', e.target.value)} required />
        <input placeholder="Last Name" value={form.profile.last_name} onChange={(e) => updateProfileField('last_name', e.target.value)} required />
        <input placeholder="Address" value={form.profile.address} onChange={(e) => updateProfileField('address', e.target.value)} required />
        <input placeholder="City" value={form.profile.city} onChange={(e) => updateProfileField('city', e.target.value)} required />
        <input placeholder="State" value={form.profile.state} onChange={(e) => updateProfileField('state', e.target.value)} required />
        <input placeholder="Blood Group" value={form.profile.blood_group} onChange={(e) => updateProfileField('blood_group', e.target.value)} required />
        <input placeholder="Latitude" value={form.profile.latitude} onChange={(e) => updateProfileField('latitude', e.target.value)} required />
        <input placeholder="Longitude" value={form.profile.longitude} onChange={(e) => updateProfileField('longitude', e.target.value)} required />
        <input placeholder="Organs (comma separated)" value={form.organ_types} onChange={(e) => setForm((prev) => ({ ...prev, organ_types: e.target.value }))} />
        <button type="submit">Create / Update Donor Profile</button>
      </form>

      <div className="tab-row top-space">
        <button onClick={loadDonorProfile}>Load My Profile</button>
        <button onClick={toggleAvailability}>Toggle Availability</button>
        <button onClick={loadNearby}>Find Nearby</button>
      </div>

      {donorMe && (
        <div className="list-block">
          <h3>My Donor Profile</h3>
          <div className="list-item">
            <div>ID: {donorMe.id}</div>
            <div>Available: {String(donorMe.is_available)}</div>
            <div>City: {donorMe.profile?.city}</div>
            <div>Blood Group: {donorMe.profile?.blood_group}</div>
          </div>
        </div>
      )}

      <div className="list-block">
        <h3>Nearby Donors</h3>
        {nearby.length === 0 && <p className="muted-text">No nearby donor results loaded yet.</p>}
        {nearby.map((item) => (
          <div key={item.donor_id} className="list-item">
            <div>{item.donor_id}</div>
            <div>{item.city}</div>
            <div>{item.blood_group}</div>
            <div>{item.distance_km} km</div>
          </div>
        ))}
      </div>
    </section>
  );
}

export default DonorPage;
